echo "[5/8] named.conf.local (zones)"
cat > /etc/bind/named.conf.local <<EOF
zone "${DOMAIN}" {
  type master;
  file "/etc/bind/zones/db.${DOMAIN}";
};

zone "${REV_ZONE}" {
  type master;
  file "/etc/bind/zones/db.${REV_PREFIX_NET}.rev";
};
EOF

echo "[6/8] Zone directe db.${DOMAIN}"
SERIAL="$(date +%Y%m%d)01"
cat > /etc/bind/zones/db.${DOMAIN} <<EOF
\$TTL ${TTL}
@   IN SOA ns1.${DOMAIN}. admin.${DOMAIN}. (
        ${SERIAL} ; Serial
        3600      ; Refresh
        900       ; Retry
        1209600   ; Expire
        300 )     ; Negative Cache
    IN NS ns1.${DOMAIN}.
;   IN NS ns2.${DOMAIN}.

ns1 IN A ${DNS1_IP}
EOF
if [[ -n "${DNS2_IP:-}" ]]; then
  echo "ns2 IN A ${DNS2_IP}" >> /etc/bind/zones/db.${DOMAIN}
fi

/etc/bind/named.conf (inclut options/local/default-zones)

/etc/bind/named.conf.options (écoute, recursion, forwarders, dnssec, logging)

/etc/bind/named.conf.local (déclarations de zones)

/etc/bind/zones/ (fichiers de zone personnalisés)

Crée le dossier zones :

bash
Copier
Modifier
sudo mkdir -p /etc/bind/zones
sudo chown bind:bind /etc/bind/zones
named.conf.options (exemple commenté)
conf
Copier
Modifier
options {
  directory "/var/cache/bind";

  // écoute
  listen-on { 10.10.0.10; 127.0.0.1; };
  listen-on-v6 { any; };

  // ACL & récursion
  acl "lan" { 10.10.0.0/24; 127.0.0.1; };
  allow-query     { any; };
  allow-recursion { "lan"; };

  // Transferts autorisés (si ns2)
  // allow-transfer { 10.10.0.11; };

allow-query     { any; };
  allow-recursion { "lan"; };

  // Transferts autorisés (si ns2)
  // allow-transfer { 10.10.0.11; };

  // Réémet les requêtes inconnues vers des DNS publics
  forwarders { 1.1.1.1; 8.8.8.8; };
  forward only;

  // DNSSEC (par défaut sur Ubuntu)
  dnssec-validation auto;

  // Rate limiting (anti-amplification)
  rate-limit {
    responses-per-second 15;
    slip 2;
  };

  // Logging minimal (voir section Logging)
  // version "not-disclosed";
};
